import { useQuery } from "@tanstack/react-query";
import { Link, useParams } from "react-router-dom";
import { plotsApi } from "@/api/client.ts";
import { RefreshProjectsCTA } from "@/components/RefreshProjectsCTA.tsx";
import { Card, CardContent } from "@/components/ui/card.tsx";
import { ActivityFeed } from "@/pages/plot-detail/activity-feed.tsx";
import {
	PlotNameEditor,
	PlotSyncButton,
	StatusTransitionControl,
} from "@/pages/plot-detail/header-controls.tsx";
import { IntentPanel } from "@/pages/plot-detail/intent-panel.tsx";
import { SubstratePanel } from "@/pages/plot-detail/substrate-panel.tsx";

/**
 * /plots/:id — three-panel Plot detail page (warren-bdbf, pl-9d6a step 13).
 *
 * Layout:
 *   - Header: name + status badge + project link.
 *   - IntentPanel  (left)   — editable goal/non_goals/constraints/success_criteria
 *                             via POST /plots/:id/intent; disabled when status
 *                             is done/archived (server also rejects with 409).
 *   - SubstratePanel (right)— attachments grouped by role + Add/Detach dialog.
 *   - ActivityFeed  (full)  — event_log timeline; collapses runs of 3+
 *                             same-kind same-actor events into a fold.
 *
 * Polling: tanstack-query with staleTime + refetchInterval at 5s
 * (mx-268674 pattern). No live event stream yet — that's deferred per
 * SPEC §11.O.Plot.UI (pl-2047 risk #6).
 *
 * Phase-7 decomposition (warren-2221 / pl-55a3 step 8): the 3000-line
 * monolith that used to live here has been split into the
 * `plot-detail/` sub-tree (header-controls, intent-panel,
 * substrate-panel, run-plan, batch-dispatch, activity-feed +
 * shared helpers). This page now owns only the
 * query, the loading / error / 404 branches, and the layout shell.
 */
export function PlotDetailPage() {
	const { id } = useParams<{ id: string }>();
	const plotId = id ?? "";

	const query = useQuery({
		queryKey: ["plot", plotId],
		queryFn: ({ signal }) => plotsApi.get(plotId, signal),
		enabled: plotId.length > 0,
		refetchInterval: 5_000,
		staleTime: 5_000,
	});

	if (plotId.length === 0) {
		return <p className="text-sm text-(--color-destructive)">Missing plot id in URL.</p>;
	}
	if (query.isLoading) {
		return <p className="text-sm text-(--color-muted-foreground)">Loading…</p>;
	}
	if (query.isError || query.data === undefined) {
		const message =
			query.error instanceof Error ? query.error.message : "Failed to load plot.";
		// warren-bb22: 404 here usually means the Plot was committed in a
		// project clone but the project hasn't been refreshed since
		// (detectProjectFeatures only flips hasPlot during refresh — see
		// mx-62ef33). Surface a refresh-all CTA so the user can recover
		// inline without bouncing to /projects.
		return (
			<Card>
				<CardContent className="space-y-3 p-4 text-sm">
					<p className="text-(--color-destructive)">{message}</p>
					<p className="text-(--color-muted-foreground)">
						If you just committed this Plot in a project clone, refresh
						projects so warren rediscovers it.
					</p>
					<RefreshProjectsCTA />
				</CardContent>
			</Card>
		);
	}

	const plot = query.data;
	const frozen = plot.status === "done" || plot.status === "archived";

	return (
		<div className="space-y-6">
			<header className="flex flex-wrap items-start justify-between gap-4">
				<div className="space-y-1">
					<PlotNameEditor plot={plot} />
					<div className="font-mono text-xs text-(--color-muted-foreground)">
						{plot.id} · project{" "}
						<Link
							to={`/projects/${encodeURIComponent(plot.project_id)}`}
							className="underline-offset-2 hover:underline"
						>
							{plot.project_id}
						</Link>
						{" · "}
						<Link
							to={`/plots/${encodeURIComponent(plot.id)}/summary`}
							className="underline-offset-2 hover:underline"
						>
							view summary
						</Link>
					</div>
				</div>
				<div className="flex flex-col items-end gap-3">
					<StatusTransitionControl plot={plot} />
					<PlotSyncButton plotId={plot.id} />
				</div>
			</header>

			<div className="grid gap-6 lg:grid-cols-2">
				<IntentPanel plot={plot} frozen={frozen} />
				<SubstratePanel plot={plot} />
			</div>

			<ActivityFeed
				plotId={plot.id}
				events={plot.event_log}
				pausedRuns={plot.paused_runs}
			/>
		</div>
	);
}

import { useQuery } from "@tanstack/react-query";
import { useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { conversationsApi, plotsApi, projectsApi } from "@/api/client.ts";
import {
	PLOT_STATUSES,
	type ConversationRow,
	type NeedsAttentionReason,
	type PlotStatus,
	type PlotSummary,
} from "@/api/types.ts";
import { NewPlotButton } from "@/components/NewPlotButton.tsx";
import { RefreshProjectsCTA } from "@/components/RefreshProjectsCTA.tsx";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import { PageHeader } from "@/components/ui/page-header.tsx";
import { relativeTime } from "@/lib/utils.ts";
import { NewConversationButton } from "./leveret/new-conversation-dialog.tsx";

const STATUS_FILTERS: { label: string; value: "all" | PlotStatus }[] = [
	{ label: "All", value: "all" },
	...PLOT_STATUSES.map((s) => ({
		label: s.charAt(0).toUpperCase() + s.slice(1),
		value: s,
	})),
];

type SortKey = "last_event_ts" | "name" | "status";
type SortDir = "asc" | "desc";

const NEEDS_ATTENTION_LABELS: Record<NeedsAttentionReason, string> = {
	paused_run: "paused run",
	merged_pr_unreviewed: "PR merged",
	stale_draft: "stale draft",
};

/**
 * /workspace — single cross-project list, one row per Plot (warren-dc54 /
 * pl-0008 step 5).
 *
 * The Plot is the durable spine; this view merges what used to live on two
 * pages (the Plots list and the Leveret conversations list) into one. Each
 * row joins a `PlotSummary` (from `plotsApi.list`, the server `?status` /
 * `?filter=needs_attention` contract still the single source of visibility
 * truth) with its active Leveret conversation (resolved client-side from
 * `conversationsApi.list`). Actions: New Plot (shared dialog) and Start
 * conversation (the existing Leveret dialog).
 */
export function WorkspacePage() {
	const [statusFilter, setStatusFilter] = useState<"all" | PlotStatus>("all");
	const [needsAttention, setNeedsAttention] = useState(false);
	const [sortKey, setSortKey] = useState<SortKey>("last_event_ts");
	const [sortDir, setSortDir] = useState<SortDir>("desc");

	const plots = useQuery({
		queryKey: ["plots", statusFilter, needsAttention ? "needs_attention" : "all"],
		queryFn: ({ signal }) =>
			plotsApi.list(
				{
					...(statusFilter === "all" ? {} : { status: statusFilter }),
					...(needsAttention ? { filter: "needs_attention" as const } : {}),
				},
				signal,
			),
		refetchInterval: 5000,
	});

	const conversations = useQuery({
		queryKey: ["conversations", "all"],
		queryFn: ({ signal }) => conversationsApi.list({}, signal),
		refetchInterval: 5000,
	});

	const projects = useQuery({
		queryKey: ["projects"],
		queryFn: ({ signal }) => projectsApi.list(signal),
	});

	const projectIndex = useMemo(() => {
		const m = new Map<string, string>();
		for (const p of projects.data?.projects ?? []) m.set(p.id, p.gitUrl);
		return m;
	}, [projects.data]);

	const hasPlotProjectCount = useMemo(
		() => (projects.data?.projects ?? []).filter((p) => p.hasPlot).length,
		[projects.data],
	);

	// Resolve the most-recent active conversation per Plot. Closed
	// conversations surface in the Plot's Activity tab (step 10), not here.
	const activeConversationByPlot = useMemo(() => {
		const m = new Map<string, ConversationRow>();
		for (const c of conversations.data?.conversations ?? []) {
			if (c.status !== "active" || !c.plotId) continue;
			const prev = m.get(c.plotId);
			if (!prev || c.lastActivityAt > prev.lastActivityAt) m.set(c.plotId, c);
		}
		return m;
	}, [conversations.data]);

	const sortedPlots = useMemo(() => {
		const rows = [...(plots.data?.plots ?? [])];
		const dir = sortDir === "asc" ? 1 : -1;
		rows.sort((a, b) => {
			let cmp = 0;
			if (sortKey === "last_event_ts") cmp = a.last_event_ts.localeCompare(b.last_event_ts);
			else if (sortKey === "name") cmp = a.name.localeCompare(b.name);
			else cmp = a.status.localeCompare(b.status);
			return cmp * dir;
		});
		return rows;
	}, [plots.data, sortKey, sortDir]);

	const handleSort = (key: SortKey): void => {
		if (sortKey === key) {
			setSortDir(sortDir === "asc" ? "desc" : "asc");
		} else {
			setSortKey(key);
			setSortDir(key === "last_event_ts" ? "desc" : "asc");
		}
	};

	const sortIndicator = (key: SortKey): string => {
		if (sortKey !== key) return "";
		return sortDir === "asc" ? " ↑" : " ↓";
	};

	return (
		<div className="space-y-6">
			<PageHeader
				title="Workspace"
				description="One row per Plot — the durable spine. Shape intent in a conversation, then plan and run, all from one place."
				actions={
					<div className="flex items-center gap-2">
						<NewConversationButton />
						<NewPlotButton destination="/workspace" />
					</div>
				}
			/>

			<div className="flex flex-wrap items-center gap-2">
				{/* Needs-you chip composes on top of the status filter
				    (server contract: ?filter+?status compose). */}
				<button
					type="button"
					onClick={() => setNeedsAttention((v) => !v)}
					aria-pressed={needsAttention}
					className={`rounded-full border px-3 py-1 text-xs transition-colors ${
						needsAttention
							? "bg-(--color-primary) text-(--color-primary-foreground)"
							: "bg-(--color-card) hover:bg-(--color-accent)"
					}`}
				>
					Needs you
				</button>
				<span aria-hidden="true" className="mx-1 h-4 w-px bg-(--color-border)" />
				{STATUS_FILTERS.map((f) => (
					<button
						key={f.value}
						type="button"
						onClick={() => setStatusFilter(f.value)}
						className={`rounded-full border px-3 py-1 text-xs transition-colors ${
							statusFilter === f.value
								? "bg-(--color-primary) text-(--color-primary-foreground)"
								: "bg-(--color-card) hover:bg-(--color-accent)"
						}`}
					>
						{f.label}
					</button>
				))}
			</div>

			<Card>
				<CardHeader>
					<CardTitle>{sortedPlots.length} plots</CardTitle>
				</CardHeader>
				<CardContent className="p-0">
					{plots.isLoading ? (
						<p className="p-6 text-sm text-(--color-muted-foreground)">Loading…</p>
					) : plots.isError ? (
						<p className="p-6 text-sm text-(--color-destructive)">
							{plots.error instanceof Error ? plots.error.message : String(plots.error)}
						</p>
					) : sortedPlots.length === 0 ? (
						<EmptyState
							hasPlotProjectCount={hasPlotProjectCount}
							statusFiltered={statusFilter !== "all"}
							needsAttention={needsAttention}
						/>
					) : (
						<WorkspaceTable
							plots={sortedPlots}
							projectLabel={(id) => projectIndex.get(id) ?? id}
							activeConversation={(id) => activeConversationByPlot.get(id)}
							sortIndicator={sortIndicator}
							onSort={handleSort}
						/>
					)}
				</CardContent>
			</Card>
		</div>
	);
}

function EmptyState({
	hasPlotProjectCount,
	statusFiltered,
	needsAttention,
}: {
	hasPlotProjectCount: number;
	statusFiltered: boolean;
	needsAttention: boolean;
}) {
	if (needsAttention) {
		return (
			<p className="p-6 text-sm text-(--color-muted-foreground)">
				Nothing needs your attention right now—every Plot is unblocked.
			</p>
		);
	}
	if (statusFiltered) {
		return (
			<p className="p-6 text-sm text-(--color-muted-foreground)">
				No plots match this status filter.
			</p>
		);
	}
	const headline =
		hasPlotProjectCount === 0
			? "No Plot-enabled projects yet — run plot init in a project clone, commit, then refresh."
			: "No plots yet. Click New Plot to create one, or refresh if you just committed one.";
	return (
		<div className="space-y-3 p-6 text-sm text-(--color-muted-foreground)">
			<p>{headline}</p>
			<RefreshProjectsCTA />
		</div>
	);
}

function WorkspaceTable({
	plots,
	projectLabel,
	activeConversation,
	sortIndicator,
	onSort,
}: {
	plots: PlotSummary[];
	projectLabel: (projectId: string) => string;
	activeConversation: (plotId: string) => ConversationRow | undefined;
	sortIndicator: (key: SortKey) => string;
	onSort: (key: SortKey) => void;
}) {
	return (
		<div className="relative w-full overflow-auto">
			<table className="w-full caption-bottom text-sm">
				<thead className="border-b">
					<tr className="text-left text-(--color-muted-foreground)">
						<th className="h-10 whitespace-nowrap px-4 font-medium">
							<button
								type="button"
								onClick={() => onSort("name")}
								className="hover:text-(--color-foreground)"
							>
								Name{sortIndicator("name")}
							</button>
						</th>
						<th className="h-10 whitespace-nowrap px-4 font-medium">Project</th>
						<th className="h-10 whitespace-nowrap px-4 font-medium">
							<button
								type="button"
								onClick={() => onSort("status")}
								className="hover:text-(--color-foreground)"
							>
								Status{sortIndicator("status")}
							</button>
						</th>
						<th className="h-10 whitespace-nowrap px-4 font-medium">Intent</th>
						<th className="h-10 whitespace-nowrap px-4 font-medium">Conversation</th>
						<th className="h-10 whitespace-nowrap px-4 font-medium">
							<button
								type="button"
								onClick={() => onSort("last_event_ts")}
								className="hover:text-(--color-foreground)"
							>
								Last activity{sortIndicator("last_event_ts")}
							</button>
						</th>
					</tr>
				</thead>
				<tbody>
					{plots.map((p) => {
						const convo = activeConversation(p.id);
						return (
							<tr key={`${p.project_id}::${p.id}`} className="border-b last:border-0">
								<td className="whitespace-nowrap px-4 py-2">
									<Link
										to={`/workspace/${encodeURIComponent(p.id)}`}
										className="font-medium underline-offset-2 hover:underline"
									>
										{p.name}
									</Link>
									<div className="font-mono text-xs text-(--color-muted-foreground)">
										{p.id}
									</div>
								</td>
								<td className="whitespace-nowrap px-4 py-2 font-mono text-xs">
									{projectLabel(p.project_id)}
								</td>
								<td className="whitespace-nowrap px-4 py-2">
									<div className="flex flex-wrap items-center gap-1">
										<span className="rounded-full border px-2 py-0.5 text-xs">
											{p.status}
										</span>
										{p.reasons?.map((r) => (
											<span
												key={r}
												className="rounded-full bg-(--color-primary)/15 px-2 py-0.5 text-xs text-(--color-primary)"
												title={`Needs you: ${r}`}
											>
												{NEEDS_ATTENTION_LABELS[r]}
											</span>
										))}
									</div>
								</td>
								<td className="max-w-[16rem] truncate px-4 py-2 text-(--color-muted-foreground)">
									{p.intent_goal_preview || "—"}
								</td>
								<td className="whitespace-nowrap px-4 py-2">
									{convo ? (
										<Link
											to={`/workspace/${encodeURIComponent(p.id)}?tab=shape`}
											className="inline-flex items-center gap-1.5 text-xs underline-offset-2 hover:underline"
											title={convo.title ?? "Active conversation"}
										>
											<span
												aria-hidden="true"
												className="inline-block h-2 w-2 rounded-full bg-(--color-primary)"
											/>
											{convo.title || "Active"}
										</Link>
									) : (
										<span className="text-xs text-(--color-muted-foreground)">—</span>
									)}
								</td>
								<td className="whitespace-nowrap px-4 py-2 text-(--color-muted-foreground)">
									<div>{relativeTime(p.last_event_ts)}</div>
									<div className="font-mono text-xs">{p.last_event_actor}</div>
								</td>
							</tr>
						);
					})}
				</tbody>
			</table>
		</div>
	);
}

